import java.io.IOException;
import java.io.StringWriter;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_withPath_callsFilesNewBufferedWriterAndReturnsCSVPrinter() throws IOException {
        Path mockPath = mock(Path.class);
        StringWriter stringWriter = new StringWriter();

        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenReturn(new java.io.BufferedWriter(stringWriter));

            CSVPrinter printer = csvFormat.print(mockPath, StandardCharsets.UTF_8);

            assertNotNull(printer);
            filesMockedStatic.verify(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8), times(1));
        }
    }

    @Test
    void testPrint_withPath_throwsIOException_whenFilesNewBufferedWriterThrows() throws IOException {
        Path mockPath = mock(Path.class);

        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenThrow(new IOException("Test IOException"));

            IOException thrown = assertThrows(IOException.class, () -> csvFormat.print(mockPath, StandardCharsets.UTF_8));
            assertEquals("Test IOException", thrown.getMessage());
        }
    }
}
